#!/usr/bin/env python3
"""
Génère 150 fichiers OpenAPI 3.0 JSON ultra-détaillés pour Agentic4API
Chaque fichier contient : endpoints complets, schemas, faux positifs documentés, breaking changes
"""

import json, os

OUT = "api-catalogue-150-detailled"
os.makedirs(OUT, exist_ok=True)

def base(api_id, title, version, status, team, domain, description, fp_warning=None, breaking_from=None, breaking_next=None, successor=None, depends_on=None):
    info = {
        "title": title, "version": version,
        "x-api-id": api_id, "x-api-version": f"v{version.split('.')[0]}",
        "x-status": status, "x-team": team, "x-domain": domain,
        "description": description
    }
    if fp_warning: info["x-false-positive-warning"] = fp_warning
    if breaking_from: info["x-breaking-changes-from-previous"] = breaking_from
    if breaking_next: info["x-breaking-changes-in-next"] = breaking_next
    if successor: info["x-successor"] = successor
    if depends_on: info["x-depends-on"] = depends_on
    return info

def err_schema():
    return {"Error":{"type":"object","properties":{"code":{"type":"string","example":"NOT_FOUND"},"message":{"type":"string"},"at":{"type":"string","format":"date-time"}}}}

def sec_schemes():
    return {"ApiKeyAuth":{"type":"apiKey","in":"header","name":"X-API-Key","description":"Clé API Kong Gateway"}}

def std_responses():
    return {
        "BadRequest":{"description":"Données invalides","content":{"application/json":{"schema":{"$ref":"#/components/schemas/Error"}}}},
        "Unauthorized":{"description":"Clé API manquante ou invalide","content":{"application/json":{"schema":{"$ref":"#/components/schemas/Error"}}}},
        "NotFound":{"description":"Ressource non trouvée","content":{"application/json":{"schema":{"$ref":"#/components/schemas/Error"}}}},
        "Conflict":{"description":"Conflit — ressource déjà existante ou état incompatible","content":{"application/json":{"schema":{"$ref":"#/components/schemas/Error"}}}}
    }

def save(api_id, doc):
    path = os.path.join(OUT, f"{api_id}.json")
    with open(path, "w", encoding="utf-8") as f:
        json.dump(doc, f, ensure_ascii=False, indent=2)
    print(f"  ✅ {api_id}.json")

SERVER = [{"url":"http://localhost:8000","description":"Kong API Gateway — Devoteam nexDigital"}]

