from collections import Counter
teams = {}
for f in files:
    with open(os.path.join(OUT, f)) as fp:
        d = json.load(fp)
        team = d["info"].get("x-team","Unknown")
        teams[team] = teams.get(team,0) + 1

print("\n  Répartition par équipe :")
for team, count in sorted(teams.items(), key=lambda x: -x[1]):
    print(f"  {team:<30} : {count:>3} APIs")